class Solution:
    def countNumbers(self, l: str, r: str, b: int) -> int:
        MOD = 10**9 + 7
        def convert_to_base(num_str, base):
            num = 0
            for digit in num_str:
                num = num * base + int(digit)
            return num

        def is_non_decreasing(num, base):
            digits = []
            while num:
                digits.append(num % base)
                num //= base
            return digits == sorted(digits)

        l_num = convert_to_base(l, b)
        r_num = convert_to_base(r, b)
        count = 0
        for i in range(l_num, r_num + 1):
            if is_non_decreasing(i, b):
                count = (count + 1) % MOD
        return count
